B.Mn=new A.c8("Merhaba! Ben Ahmet Y\u0131lmaz. Necmettin Erbakan \xdcniversitesi Matematik Bilgisayar bilimleri b\xf6l\xfcm\xfc \xf6\u011frencisi ve tutkulu bir Flutter geli\u015ftiricisiyim. Akademik kariyerim boyunca, matematiksel analiz, algoritmalar ve veri yap\u0131lar\u0131 \xfczerine g\xfc\xe7l\xfc bir temel olu\u015ftururken, yaz\u0131l\u0131m konusunda da kendimi geli\u015ftirdim.",null,B.db,null,null)
B.uI=new A.et(null,8,null,null)
B.Mc=new A.c8("\xd6zellikle mobil uygulama geli\u015ftirme alan\u0131nda b\xfcy\xfck bir ilgiye sahibim ve Flutter kullanarak \xe7e\u015fitli projeler geli\u015ftirdim. Kullan\u0131c\u0131 dostu ve performans odakl\u0131 mobil uygulamalar geli\u015ftirme s\xfcrecinde \xf6\u011frendi\u011fim modern teknikleri ve en iyi uygulamalar\u0131 projelerime uygulamaktan b\xfcy\xfck keyif al\u0131yorum.",null,B.db,null,null)
B.bF=new A.et(null,16,null,null)
B.Ma=new A.c8("Problem \xe7\xf6zme ve analitik d\xfc\u015f\xfcnme yeteneklerimi yaz\u0131l\u0131m geli\u015ftirme s\xfcre\xe7lerinde etkin bir \u015fekilde kullan\u0131yorum. Ayn\u0131 zamanda, farkl\u0131 teknolojileri \xf6\u011frenmeye a\xe7\u0131k biriyim ve s\xfcrekli olarak kendimi geli\u015ftirmeye \xe7al\u0131\u015f\u0131yorum. Teknik becerilerimin yan\u0131 s\u0131ra, disiplinli ve detaylara \xf6nem veren bir yap\u0131ya sahibim. Kendi projelerimde \xf6\u011frendiklerimi hayata ge\xe7irerek, yenilik\xe7i \xe7\xf6z\xfcmler geli\u015ftirmeye ve kullan\u0131c\u0131 deneyimini en \xfcst d\xfczeye \xe7\u0131karmaya odaklan\u0131yorum.",null,B.db,null,null)
B.Mf=new A.c8("Kariyerime, mobil uygulama geli\u015ftirme alan\u0131nda kendimi daha da geli\u015ftirebilece\u011fim ve \xf6\u011frendiklerimi ger\xe7ek d\xfcnya projelerine uygulayabilece\u011fim bir rolde devam etmek istiyorum. Hedefim, hem bireysel hem de tak\u0131m olarak ba\u015far\u0131l\u0131 projelere imza atarak, teknoloji d\xfcnyas\u0131nda de\u011fer yaratmak.",null,B.db,null,null)
B.Mg=new A.c8("E\u011fer ba\u011flant\u0131 kurmak veya i\u015fbirli\u011fi yapmak isterseniz, l\xfctfen benimle ileti\u015fime ge\xe7mekten \xe7ekinmeyin!",null,B.db,null,null)
